#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

struct Node{
    int x,y,id;
}p[N];

bool cmp1(Node u,Node v){
    return u.x<v.x;
}

bool cmp2(Node u,Node v){
    return u.y<v.y;
}

int n,fx[N][2],fy[N][2],ans[N];

void init(){
    sort(p+1,p+n+1,cmp1);
    fx[0][0]=N;
    for(int i=1;i<=n;i++)
        fx[i][0]=min(fx[i-1][0],p[i].y);
    for(int i=n;i;i--)
        fx[i][1]=max(fx[i+1][1],p[i].y);
    sort(p+1,p+n+1,cmp2);
    fy[0][0]=N;
    for(int i=1;i<=n;i++)
        fy[i][0]=min(fy[i-1][0],p[i].x);
    for(int i=n;i;i--)
        fy[i][1]=max(fy[i+1][1],p[i].x);
}

void solve(){
    for(int i=1;i<=n;){
        int tp=0,lx=0,ly=0,px=p[i].x,py=p[i].y,r;
        while(1){
            int tx=fy[py][tp],ty=fx[px][tp];
            if(tx==lx && ty==ly){
                if(tp)
                    r=ly;
                else
                    r=py;
                break;
            }
            lx=px,ly=py,px=tx,py=ty,tp^=1;
        }
        for(int j=i;j<=r;j++)
            ans[p[j].id]=r-i+1;
        i=r+1;
    }
}

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&p[i].x,&p[i].y);
        p[i].id=i;
    }

    init();
    solve();

    for(int i=1;i<=n;i++)
        printf("%d\n",ans[i]);
    return 0;
}
